            # Prioritize 'YYYY' at the end, then 'YYYY' after 'dated' or 'of'
            if len(date_str) > 4 and date_str[-4:].isdigit():
                return int(date_str[-4:])
            elif 'dated' in date_str:
                parts = date_str.split('dated')
                if len(parts) > 1 and parts[1].strip()[-4:].isdigit():
                    return int(parts[1].strip()[-4:])
            elif 'of' in date_str:
                parts = date_str.split('of')
                if len(parts) > 1 and parts[1].strip()[-4:].isdigit():
                    return int(parts[1].strip()[-4:])
            # Fallback for simpler cases like 'July 1st, 2019'
            for fmt in ("%B %dth, %Y", "%B %dst, %Y", "%B %dnd, %Y", "%B %drd, %Y", "%dth %B %Y", "%dst %B %Y", "%dnd %B %Y", "%drd %B %Y"):
                try:
                    return pd.to_datetime(date_str.replace("the ", ""), format=fmt).year
                except ValueError:
                    pass
            # More general date parsing for cases like "21st of September, 2021" or "3rd August 2021"
            # Attempt to find a 4-digit year string
            words = date_str.split()
            for word in words:
                if len(word) == 4 and word.isdigit():
                    return int(word)
        return None
    except:
        return None

df['grant_year'] = df['grant_date'].apply(parse_grant_date)

def parse_grant_month(date_str):
    try:
        if isinstance(date_str, str):
            for fmt in ("%B %dth, %Y", "%B %dst, %Y", "%B %dnd, %Y", "%B %drd, %Y", "%dth %B %Y", "%dst %B %Y", "%dnd %B %Y", "%drd %B %Y"):
                try:
                    return pd.to_datetime(date_str.replace("the ", ""), format=fmt).month
                except ValueError:
                    pass
            # For cases like "3rd August 2021", extract month name and convert to number
            months = {
                'january': 1, 'february': 2, 'march': 3, 'april': 4, 'may': 5, 'june': 6,
                'july': 7, 'august': 8, 'september': 9, 'october': 10, 'november': 11, 'december': 12
            }
            date_str_lower = date_str.lower()
            for month_name, month_num in months.items():
                if month_name in date_str_lower:
                    return month_num
